def calculate_ilc_length(energy_gev):
    # Approximate length (km) based on energy stage (GeV)
    if energy_gev == 250:
        return 20
    elif energy_gev == 500:
        return 40  # Mid-range estimate
    elif energy_gev == 1000:
        return 50  # Upper estimate
    else:
        return None  # Unsupported energy stage

# Example usage:
print(calculate_ilc_length(500))  # Output: 40

The function returns the approximate length of the ILC in kilometers for given energy stages (250 GeV, 500 GeV, or 1 TeV).
